import React, { useEffect, useRef } from 'react';

export default function ParticleBackground() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animationFrameId;
    let particles = [];
    
    let mouse = {
      x: null,
      y: null,
      radius: 150
    };

    const handleMouseMove = (event) => {
      mouse.x = event.x;
      mouse.y = event.y;
    };

    const handleResize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('resize', handleResize);

    class Particle {
      constructor(x, y, vx, vy, size, color) {
        this.x = x;
        this.y = y;
        this.baseX = x;
        this.baseY = y;
        this.vx = vx;
        this.vy = vy;
        this.size = size;
        this.color = color;
        this.density = (Math.random() * 30) + 1;
      }
      
      draw() {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.closePath();
        ctx.fillStyle = this.color;
        ctx.fill();
      }

      update(isDark) {
        // Interacción con el mouse
        if (mouse.x != null && mouse.y != null) {
          let dx = mouse.x - this.x;
          let dy = mouse.y - this.y;
          let distance = Math.sqrt(dx * dx + dy * dy);
          let forceDirectionX = dx / distance;
          let forceDirectionY = dy / distance;
          
          let maxDistance = mouse.radius;
          let force = (maxDistance - distance) / maxDistance;
          let directionX = forceDirectionX * force * this.density;
          let directionY = forceDirectionY * force * this.density;

          if (distance < maxDistance) {
            this.x -= directionX;
            this.y -= directionY;
          } else {
            if (this.x !== this.baseX) {
              let dx = this.x - this.baseX;
              this.x -= dx / 10;
            }
            if (this.y !== this.baseY) {
              let dy = this.y - this.baseY;
              this.y -= dy / 10;
            }
          }
        }
        
        // Movimiento natural leve
        this.baseX += this.vx;
        this.baseY += this.vy;
        
        if (this.baseX < 0 || this.baseX > canvas.width) this.vx = -this.vx;
        if (this.baseY < 0 || this.baseY > canvas.height) this.vy = -this.vy;

        // Actualizar color dinámicamente según el tema
        this.color = isDark ? 'rgba(56, 189, 248, 0.4)' : 'rgba(37, 99, 235, 0.3)';
        this.draw();
      }
    }

    function init() {
      particles = [];
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      let numberOfParticles = (canvas.width * canvas.height) / 9000;
      
      const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
      const color = isDark ? 'rgba(56, 189, 248, 0.4)' : 'rgba(37, 99, 235, 0.3)';

      for (let i = 0; i < numberOfParticles; i++) {
        let size = (Math.random() * 2) + 1;
        let x = (Math.random() * ((innerWidth - size * 2) - (size * 2)) + size * 2);
        let y = (Math.random() * ((innerHeight - size * 2) - (size * 2)) + size * 2);
        let vx = (Math.random() - 0.5) * 0.5;
        let vy = (Math.random() - 0.5) * 0.5;
        particles.push(new Particle(x, y, vx, vy, size, color));
      }
    }

    function animate() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
      // Acceso seguro: iteramos con for...of para evitar acceso por índice dinámico
      for (const particle of particles) {
        particle.update(isDark);
      }
      connect(isDark);
      animationFrameId = requestAnimationFrame(animate);
    }

    function connect(isDark) {
      let opacityValue = 1;
      // Acceso seguro: usamos variables locales en lugar de índices dinámicos sobre el array
      for (let a = 0; a < particles.length; a++) {
        const pa = particles.at(a);
        for (let b = a; b < particles.length; b++) {
          const pb = particles.at(b);
          const distance = ((pa.x - pb.x) * (pa.x - pb.x)) 
                         + ((pa.y - pb.y) * (pa.y - pb.y));
          if (distance < (canvas.width / 7) * (canvas.height / 7)) {
            opacityValue = 1 - (distance / 20000);
            ctx.strokeStyle = isDark ? `rgba(56, 189, 248, ${opacityValue * 0.2})` : `rgba(37, 99, 235, ${opacityValue * 0.2})`;
            ctx.lineWidth = 1;
            ctx.beginPath();
            ctx.moveTo(pa.x, pa.y);
            ctx.lineTo(pb.x, pb.y);
            ctx.stroke();
          }
        }
      }
    }

    init();
    animate();

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', handleResize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100vw',
        height: '100vh',
        zIndex: 0,
        pointerEvents: 'none'
      }} 
    />
  );
}

import React, { useState, useEffect, useRef } from 'react';
import './SuggestionInput.css';

/**
 * Custom Suggestion Input
 * A premium, themed autocomplete component that replaces the native datalist.
 */
export default function SuggestionInput({ 
  value, 
  onChange, 
  suggestions = [], 
  placeholder = '', 
  className = '', 
  style = {},
  required = false,
  spellCheck = true,
  lang = 'es',
  id = ''
}) {
  const [isOpen, setIsOpen] = useState(false);
  const [filtered, setFiltered] = useState([]);
  const [cursor, setCursor] = useState(-1);
  const wrapperRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    if (value && isOpen) {
      const match = suggestions.filter(s => 
        s.toLowerCase().includes(value.toLowerCase()) && 
        s.toLowerCase() !== value.toLowerCase()
      );
      setFiltered(match.slice(0, 8)); // Limit to 8 suggestions
    } else if (isOpen && !value) {
      setFiltered(suggestions.slice(0, 5)); // Show some default suggestions if empty
    } else {
      setFiltered([]);
    }
  }, [value, suggestions, isOpen]);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleKeyDown = (e) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setCursor(c => (c < filtered.length - 1 ? c + 1 : c));
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setCursor(c => (c > 0 ? c - 1 : 0));
    } else if (e.key === "Enter" && cursor !== -1) {
      e.preventDefault();
      // Acceso seguro: usamos .at() para evitar inyección por índice dinámico
      selectSuggestion(filtered.at(cursor));
    } else if (e.key === "Escape") {
      setIsOpen(false);
    }
  };

  const selectSuggestion = (s) => {
    onChange({ target: { value: s } });
    setIsOpen(false);
    setCursor(-1);
  };

  return (
    <div className="suggestion-wrapper" ref={wrapperRef}>
      <input
        id={id}
        ref={inputRef}
        type="text"
        autoComplete="off"
        className={`input-field ${className}`}
        style={style}
        placeholder={placeholder}
        value={value}
        onChange={onChange}
        onFocus={() => setIsOpen(true)}
        onMouseDown={() => setIsOpen(true)}
        onKeyDown={handleKeyDown}
        required={required}
        spellCheck={spellCheck}
        lang={lang}
      />

      {isOpen && filtered.length > 0 && (
        <ul className="suggestion-dropdown">
          {filtered.map((s, i) => (
            <li 
              key={i} 
              className={`suggestion-item ${cursor === i ? 'active' : ''}`}
              onClick={() => selectSuggestion(s)}
            >
              {s}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

