        )}

        {/* ══════════ MONITOREO TAB ══════════ */}
        {tab === 'monitoreo' && (
          <div className="animate-fade-in">
            {monitorLoad ? (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '4rem', gap: '1rem', color: 'var(--text-3)' }}>
